"""Correlation HTTP handlers (v1 envelopes)."""from __future__ import annotationsfrom typing import Anyfrom src.api.handlers.v1_envelopes import correlation_context_v1_envelope, correlation_ingest_v1_envelopefrom src.services.async_read.correlation import AsyncCorrelationReadServicefrom src.services.async_write.correlation import AsyncCorrelationWriteServiceasync def handle_correlation_context(service: AsyncCorrelationReadService, resource_ids: list[int], depth: int):    ctx = await service.build_context(resource_ids, depth=depth)    return correlation_context_v1_envelope(ctx)async def handle_correlation_ingest(    service: AsyncCorrelationWriteService,    alerts: list[dict[str, Any]],    *,    source: str | None = None,    depth: int = 3,    page: int = 1,    page_size: int | None = None,    webhook_url: str | None = None,    dispatch_webhook: bool = False,):    result = await service.ingest(        alerts,        source=source,        depth=depth,        page=page,        page_size=page_size,        webhook_url=webhook_url,        dispatch_webhook=dispatch_webhook,    )    return correlation_ingest_v1_envelope(result)